INSERT INTO test_cases (`key`, tc_no, feature_key, system_name, detail_index, title, precondition, steps, actual_result, test_url, status, tester, test_date, remark) VALUES ('tc_1777349856864_0', 'TC-ADM-001', NULL, '1.ระบบผู้ดูแลระบบ', 0, '1.1 กำหนดข้อมูลหน่วยงาน - แสดงหน้าจอ', '1. ระบบ BMS Accounting รันที่ http://localhost:60\n2. Login ด้วย user ที่มีสิทธิ์เข้าถึง "1.ระบบผู้ดูแลระบบ"\n3. URL ที่ทดสอบ: http://localhost:60/mainsetting/organization', '[{"action":"เข้าเมนู ตั้งค่าระบบบัญชี > หน่วยงาน"},{"action":"ตรวจสอบหน้าจอแสดงผล"}]', 'หน้าจอตั้งค่าองค์กรแสดงฟอร์มกรอกข้อมูล ชื่อหน่วยงาน ที่อยู่ เลขที่ผู้เสียภาษี และตัวเลือกภาษี', '/mainsetting/organization', 'pass', 'QA Team', '2026-04-28', 'หน้าจอแสดงผลครบถ้วน มีชื่อหน่วยงาน ที่อยู่ เลขผู้เสียภาษี การตั้งค่าภาษี VAT และการออกเลขวางบิล');
INSERT INTO test_cases (`key`, tc_no, feature_key, system_name, detail_index, title, precondition, steps, actual_result, test_url, status, tester, test_date, remark) VALUES ('tc_1777349856876_1', 'TC-ADM-002', NULL, '1.ระบบผู้ดูแลระบบ', 0, '1.1 กำหนดข้อมูลหน่วยงาน - บันทึกข้อมูล', '1. ระบบ BMS Accounting รันที่ http://localhost:60\n2. Login ด้วย user ที่มีสิทธิ์เข้าถึง "1.ระบบผู้ดูแลระบบ"\n3. URL ที่ทดสอบ: http://localhost:60/mainsetting/organization', '[{"action":"เข้าหน้าตั้งค่าองค์กร"},{"action":"กรอกชื่อหน่วยงาน ที่อยู่ เลขที่ผู้เสียภาษี"},{"action":"เลือก/ยกเลิก VAT"},{"action":"กดปุ่มบันทึก"}]', 'ระบบบันทึกข้อมูลหน่วยงานสำเร็จ และแสดงข้อความยืนยัน', '/mainsetting/organization', 'pass', 'QA Team', '2026-04-28', 'ปุ่มบันทึกทำงานได้ ฟอร์มครบ');
INSERT INTO test_cases (`key`, tc_no, feature_key, system_name, detail_index, title, precondition, steps, actual_result, test_url, status, tester, test_date, remark) VALUES ('tc_1777349856891_2', 'TC-ADM-003', NULL, '1.ระบบผู้ดูแลระบบ', 0, '1.2 กำหนดปีงบทำการ - แสดงรายการ', '1. ระบบ BMS Accounting รันที่ http://localhost:60\n2. Login ด้วย user ที่มีสิทธิ์เข้าถึง "1.ระบบผู้ดูแลระบบ"\n3. URL ที่ทดสอบ: http://localhost:60/mainsetting/fiscal-years', '[{"action":"เข้าเมนู ตั้งค่าระบบบัญชี > ปีงบทำการ"},{"action":"ตรวจสอบรายการปีงบประมาณที่แสดง"}]', 'แสดงตารางรายการปีงบประมาณ มีข้อมูล ปีงบประมาณ วันเริ่มต้น วันสิ้นสุด สถานะ', '/mainsetting/fiscal-years', 'pass', 'QA Team', '2026-04-28', 'แสดงตารางปีงบประมาณ พร้อมข้อมูลครบถ้วน มีข้อมูล 1 รายการ (2569)');
